#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int reposts[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &reposts[i]);
    }
    int people = 0;
    for (int i = 0; i < n; i++) {
        if (reposts[i] > 0) {
            people++;
        }
    }
    printf("%d\n", people);
    return 0;
}

