code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] reposts = new int[n];
        for (int i = 0; i < n; i++) {
            reposts[i] = scanner.nextInt();
        }
        int people = 0;
        for (int i = 0; i < n; i++) {
            if (reposts[i] > 0) {
                people++;
            }
        }
        System.out.println(people);
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let reposts;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        reposts = input.split(' ').map(Number);
        let people = 0;
        for (let i = 0; i < n; i++) {
            if (reposts[i] > 0) {
                people++;
            }
        }
        console.log(people);
        rl.close();
    }
});
